import { revalidateTag, unstable_cache } from 'next/cache';
import { getAllProducts } from '../lib/db';

const getCachedProducts = unstable_cache(
  async () => {
    return getAllProducts();
  },
  ['products'],
  {
    tags: ['products']
  }
);

async function syncLatestCatalog() {
  'use server';

  revalidateTag('products');
}

export default async function Page() {
  const products = await getCachedProducts();

  return (
    <main style={{ fontFamily: 'Arial, sans-serif', padding: '2rem', maxWidth: 960, margin: '0 auto' }}>
      <h1 style={{ marginBottom: '0.5rem' }}>Product Catalog</h1>
      <p style={{ color: '#555', marginTop: 0, marginBottom: '1.5rem' }}>
        Browse catalog data quickly with background refreshes when the upstream ERP/PIM changes.
      </p>

      <form action={syncLatestCatalog} style={{ marginBottom: '1.5rem' }}>
        <button
          type="submit"
          style={{
            background: '#111827',
            color: 'white',
            border: 0,
            borderRadius: 8,
            padding: '0.75rem 1rem',
            fontSize: '0.95rem',
            cursor: 'pointer'
          }}
        >
          Sync latest catalog
        </button>
      </form>

      <div style={{ border: '1px solid #e5e7eb', borderRadius: 12, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              <th style={thStyle}>SKU</th>
              <th style={thStyle}>Product</th>
              <th style={thStyle}>Price</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderTop: '1px solid #e5e7eb' }}>
                <td style={tdStyle}>{product.id}</td>
                <td style={tdStyle}>{product.name}</td>
                <td style={tdStyle}>${product.price.toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}

const thStyle: React.CSSProperties = {
  textAlign: 'left',
  padding: '0.875rem 1rem',
  fontSize: '0.85rem',
  color: '#374151',
  letterSpacing: '0.02em'
};

const tdStyle: React.CSSProperties = {
  padding: '0.875rem 1rem',
  fontSize: '0.95rem',
  color: '#111827'
};

